CREATE TABLE blinkit_orders (
    `Order_ID` VARCHAR(255),
    `Order_Date` VARCHAR(255),
    `Order_Month` VARCHAR(255),
    `Order_Quarter` VARCHAR(255),
    `City` VARCHAR(255),
    `Category` VARCHAR(255),
    `Product_Name` VARCHAR(255),
    `Quantity` INT,
    `Unit_Price_INR` DECIMAL(18,2),
    `Gross_Amount_INR` DECIMAL(18,2),
    `Discount_Pct` INT,
    `Discount_Amount_INR` DECIMAL(18,2),
    `Net_Amount_INR` DECIMAL(18,2),
    `Delivery_Fee_INR` INT,
    `Final_Amount_INR` DECIMAL(18,2),
    `Payment_Method` VARCHAR(255),
    `Delivery_Time_Mins` INT,
    `Order_Status` VARCHAR(255),
    `Customer_Rating` DECIMAL(18,2),
    `Dark_Store_ID` VARCHAR(255)
);

